#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int min(int a, int b) { return a < b ? a : b; }

int eval(int* nums, int n, int* ops) {
    int res = nums[0];
    for (int i = 1; i < n; i++) {
        if (ops[i-1] == 0) res += nums[i];
        else if (ops[i-1] == 1) res -= nums[i];
        else res *= nums[i];
    }
    return res;
}

void backtrack(int* nums, int n, int* ops, int idx, int* min_val) {
    if (idx == n-1) {
        int val = eval(nums, n, ops);
        if (val < *min_val) *min_val = val;
        return;
    }
    for (int i = 0; i < 3; i++) {
        ops[idx] = i;
        backtrack(nums, n, ops, idx+1, min_val);
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int* nums = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) scanf("%d", &nums[i]);
        int* ops = (int*)malloc((n-1) * sizeof(int));
        int min_val = 1000000000;
        backtrack(nums, n, ops, 0, &min_val);
        printf("%d\n", min_val);
        free(nums);
        free(ops);
    }
    return 0;
}

